// Script Continued Below
// 2.8.5 | 2024-12-05 | RAJ  |  ServiceNow Certifier Update - Modified to use GlideStringUtil.escapeQueryTermSeparator
// 2.7.0 | 2021-11-18 | raj  | STRY0114416 - 4 - 2.7 Certification Fixes
(function executeRule(current, previous /*null when async*/) {

	// STRY0050440
	var userInfoScript = new UserInfoScripts();
	if(!userInfoScript.userCanCreateOU(current.parent)){
		gs.addInfoMessage('Action not authorized');
		current.setAbortAction(true);
		return;
	}


	var table = "x_153465_discovert_discover_office_hierarchy";
	// STRY0114416 - 4
	var gr_Org_Dup = new GlideRecordSecure(table);
	// ServiceNow Certifier Update - not changing, no way for user to inject into this query - update later with more time
	gr_Org_Dup.addEncodedQuery('office_name='+ current.office_name+'^ORoffice_abbreviation=' + current.office_abbreviation);

	gr_Org_Dup.query();

	if (gr_Org_Dup.next() && gr_Org_Dup.sys_id != current.sys_id) {
		var grOfficeAbbreviation = gr_Org_Dup.office_abbreviation.toUpperCase();
		var grOfficeName = gr_Org_Dup.office_name.toUpperCase() ;

		if( grOfficeAbbreviation ==  current.office_abbreviation.toUpperCase()){
			gs.addErrorMessage("The OU Abbreviation already exists.  In order to create a new OU, the OU Abbreviation must be unique.");
		}

		if( grOfficeName ==  current.office_name.toUpperCase()){
			gs.addErrorMessage("The OU Name already exists. In order to create a new OU, the OU Name must be unique.");
		}
		current.setAbortAction(true);


	}

})(current, previous);
